"""sklearn.dummy — Baseline estimators that ignore input features."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, RegressorMixin


class DummyClassifier(BaseEstimator, ClassifierMixin):
    """Classifier that makes predictions using simple rules.

    Parameters
    ----------
    strategy : str, default='most_frequent'
        One of 'most_frequent', 'stratified', 'uniform', 'constant'.
    constant : any, default=None
        Predicted class when strategy='constant'.
    random_state : int or None, default=None
    """

    def __init__(self, strategy='most_frequent', constant=None, random_state=None):
        self.strategy = strategy
        self.constant = constant
        self.random_state = random_state

    def fit(self, X, y):
        self.classes_ = np.unique(y)
        y = np.asarray(y)
        self.class_prior_ = np.array([np.mean(y == c) for c in self.classes_])
        if self.strategy == 'constant' and self.constant is None:
            raise ValueError("constant must be set when strategy='constant'")
        return self

    def predict(self, X):
        n = np.asarray(X).shape[0]
        rng = np.random.RandomState(self.random_state)
        if self.strategy == 'most_frequent':
            return np.full(n, self.classes_[np.argmax(self.class_prior_)])
        elif self.strategy == 'stratified':
            return rng.choice(self.classes_, size=n, p=self.class_prior_)
        elif self.strategy == 'uniform':
            return rng.choice(self.classes_, size=n)
        elif self.strategy == 'constant':
            return np.full(n, self.constant)
        raise ValueError("Unknown strategy: %s" % self.strategy)


class DummyRegressor(BaseEstimator, RegressorMixin):
    """Regressor that makes predictions using simple rules.

    Parameters
    ----------
    strategy : str, default='mean'
        One of 'mean', 'median', 'constant'.
    constant : float or None, default=None
    """

    def __init__(self, strategy='mean', constant=None):
        self.strategy = strategy
        self.constant = constant

    def fit(self, X, y):
        y = np.asarray(y, dtype=float)
        self.constant_ = {
            'mean': np.mean(y),
            'median': np.median(y),
            'constant': self.constant,
        }[self.strategy]
        if self.constant_ is None:
            raise ValueError("constant must be set when strategy='constant'")
        return self

    def predict(self, X):
        n = np.asarray(X).shape[0]
        return np.full(n, self.constant_)
